const tags = ['Agent Pods'];

const MIN_TERMINAL_PORT = 1024;
const MAX_TERMINAL_PORT = 65535;

function validateTerminalPort(port: number): number {
  if (!Number.isInteger(port) || port < MIN_TERMINAL_PORT || port > MAX_TERMINAL_PORT) {
    throw new Error(
      `terminalPort must be an integer between ${MIN_TERMINAL_PORT} and ${MAX_TERMINAL_PORT}`,
    );
  }
  return port;
}

const terminalAccessCache = new Map<string, { access: AgentServiceAccess; timestamp: number }>();
const TERMINAL_URL_CACHE_TTL = 30 * 1000;

function terminalCacheKey(namespace: string, agentId: string): string {
  return `${namespace}/${agentId}`;
}

function getCachedTerminalAccess(
  namespace: string,
  agentId: string,
): AgentServiceAccess | undefined {
  const key = terminalCacheKey(namespace, agentId);
  const entry = terminalAccessCache.get(key);
  if (!entry) return undefined;
  if (Date.now() - entry.timestamp > TERMINAL_URL_CACHE_TTL) {
    terminalAccessCache.delete(key);
    return undefined;
  }
  return entry.access;
}

function setCachedTerminalAccess(
  namespace: string,
  agentId: string,
  access: AgentServiceAccess,
): void {
  const key = terminalCacheKey(namespace, agentId);
  terminalAccessCache.set(key, { access, timestamp: Date.now() });
}

function clearCachedTerminalAccess(namespace: string, agentId: string): void {
  terminalAccessCache.delete(terminalCacheKey(namespace, agentId));
}

